fetch("json/products.json").then(e=>e.json()).then(products=>{
  let grid=document.querySelector(".grid"),
      menuLinks=document.querySelectorAll(".categories-menu a");
  function filter(category="All"){
    grid.innerHTML="";
    products.filter(p=>"All"===category||p.category===category)
            .forEach(p=>{
              let a=document.createElement("a");
              a.href="product.html?id="+p.id;
              a.className="item-link";
              let img=document.createElement("img");
              img.src=p.images[0];
              img.alt=p.name;
              let h3=document.createElement("h3");
              h3.textContent=p.name;
              let pDesc=document.createElement("p");
              pDesc.textContent=p.description;
              a.append(img,h3,pDesc);
              grid.appendChild(a);
            });
  }
  filter();
  menuLinks.forEach(link=>{
    link.addEventListener("click",e=>{
      e.preventDefault();
      let cat=link.dataset.category;
      filter(cat);
      menuLinks.forEach(l=>l.classList.remove("active"));
      link.classList.add("active");
    });
  });
});
